  'ref.myReferrals': { it: 'I miei invitati', tr: 'Davetlilerim', wo: 'Samay woote', sw: 'Walioalikwa wangu' },
  'ref.noReferral': { it: 'Nessun invitato per ora. Condividi il tuo link per iniziare a guadagnare.', tr: 'Henüz davetli yok. Kazanmaya başlamak için bağlantınızı paylaşın.', wo: 'Amaguloo woote. Seddool sa lëkk ngir tàmbali jariñoo.', sw: 'Hakuna walioalikwa bado. Shiriki kiungo chako kuanza kupata.' },
