  // ── Page Guides ──
  'guides.subSuper': { it: 'Come super-amministratore, hai accesso a tutte le guide.', tr: 'Süper yönetici olarak tüm kılavuzlara erişiminiz var.', wo: 'Yaw njiit lu mag li, mën nga jot téere yépp.', sw: 'Kama msimamizi mkuu, una idhini ya miongozo yote.' },
  'guides.subOwn': { it: 'La guida dedicata al tuo spazio, per un uso autonomo.', tr: 'Alanınıza özel kılavuz — kendi başınıza kullanım için.', wo: 'Téere bi ñu jagleel sa barab, ngir nga mën cee dox sa bopp.', sw: 'Mwongozo maalum wa eneo lako, kwa matumizi huru.' },
  'guides.none': { it: 'Nessuna guida disponibile per il tuo profilo.', tr: 'Profiliniz için kılavuz yok.', wo: 'Amul téere ngir sa profil.', sw: 'Hakuna mwongozo kwa wasifu wako.' },
  'guides.word': { it: 'Guida', tr: 'Kılavuz', wo: 'Téere', sw: 'Mwongozo' },
  'guides.readPdf': { it: 'Leggi il PDF', tr: "PDF'yi oku", wo: 'Jàng PDF bi', sw: 'Soma PDF' },
  'guides.role.parent': { it: 'Genitore', tr: 'Veli', wo: 'Waajur', sw: 'Mzazi' },
  'guides.role.coach': { it: 'Coach', tr: 'Koç', wo: 'Coach', sw: 'Kocha' },
  'guides.role.commercial': { it: 'Commerciale', tr: 'Satış ortağı', wo: 'Komersaal', sw: 'Wakala' },
  'guides.role.admin': { it: 'Admin', tr: 'Yönetici', wo: 'Njiit', sw: 'Msimamizi' },
  'guides.role.super-admin': { it: 'Super-Admin', tr: 'Süper yönetici', wo: 'Njiit lu mag', sw: 'Msimamizi mkuu' },
  'guides.desc.parent': { it: 'Trovare, prenotare e seguire un coach per i tuoi figli.', tr: 'Çocuklarınız için koç bulma, ayırtma ve takip.', wo: 'Gis, réserve te topp ab coach ngir say doom.', sw: 'Kupata, kuhifadhi na kufuatilia kocha kwa watoto wako.' },
  'guides.desc.coach': { it: 'Costruire il tuo profilo, ricevere incarichi, seguire i guadagni.', tr: 'Profil oluşturma, görev alma, kazanç takibi.', wo: 'Defar sa profil, jot ay liggéey, topp say njariñ.', sw: 'Kujenga wasifu wako, kupokea kazi, kufuatilia mapato.' },
  'guides.desc.commercial': { it: 'Reclutare genitori e coach, seguire invitati e guadagni.', tr: 'Veli ve koç kazandırma; davetli ve kazanç takibi.', wo: 'Indi waajur ak coach, topp say woote ak njariñ.', sw: 'Kusajili wazazi na makocha, kufuatilia walioalikwa na mapato.' },
  'guides.desc.admin': { it: 'Gestire utenti, convalidare coach, seguire le finanze.', tr: 'Kullanıcı yönetimi, koç onayı, finans takibi.', wo: 'Toppatoo jëfandikukat yi, wóorlu coach yi, topp xaalis bi.', sw: 'Kusimamia watumiaji, kuthibitisha makocha, kufuatilia fedha.' },
